import numpy as np

class DecisionTree:
    def __init__(self, max_depth=5):
        self.max_depth = max_depth
        self.tree = None

    def fit(self, X, y):
        self.tree = self._build_tree(X, y, depth=0)

    def _build_tree(self, X, y, depth):
        n_samples, n_features = X.shape
        n_classes = len(np.unique(y))

        if depth >= self.max_depth or n_classes == 1:
            return {'leaf': True, 'class': np.bincount(y).argmax()}

        # Find best split
        best_gain = -1
        best_feature = None

        for feature in range(n_features):
            thresholds = np.unique(X[:, feature])
            for threshold in thresholds:
                left = X[:, feature] <= threshold
                right = ~left
                gain = self._information_gain(y, y[left], y[right])
                if gain > best_gain:
                    best_gain = gain
                    best_feature = feature
                    best_threshold = threshold

        if best_gain == -1:
            return {'leaf': True, 'class': np.bincount(y).argmax()}

        left_idx = X[:, best_feature] <= best_threshold
        right_idx = ~left_idx

        return {
            'leaf': False,
            'feature': best_feature,
            'threshold': best_threshold,
            'left': self._build_tree(X[left_idx], y[left_idx], depth+1),
            'right': self._build_tree(X[right_idx], y[right_idx], depth+1)
        }

    def _information_gain(self, parent, left, right):
        def gini(y):
            if len(y) == 0: return 0
            counts = np.bincount(y)
            probs = counts / len(y)
            return 1 - np.sum(probs ** 2)

        n = len(parent)
        if n == 0: return 0
        return gini(parent) - (len(left)/n)*gini(left) - (len(right)/n)*gini(right)

import numpy as np

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers
        self.weights = []
        self.biases = []
        self._initialize_weights()

    def _initialize_weights(self):
        for i in range(len(self.layers) - 1):
            w = np.random.randn(self.layers[i], self.layers[i+1]) * 0.1
            b = np.zeros((1, self.layers[i+1]))
            self.weights.append(w)
            self.biases.append(b)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-np.clip(x, -500, 500)))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward(self, X):
        self.activations = [X]
        for w, b in zip(self.weights, self.biases):
            z = np.dot(self.activations[-1], w) + b
            self.activations.append(self.sigmoid(z))
        return self.activations[-1]

    def backward(self, X, y, learning_rate=0.1):
        m = X.shape[0]
        deltas = [None] * len(self.weights)

        error = y - self.activations[-1]
        deltas[-1] = error * self.sigmoid_derivative(self.activations[-1])

        for i in range(len(deltas) - 2, -1, -1):
            error = deltas[i+1].dot(self.weights[i+1].T)
            deltas[i] = error * self.sigmoid_derivative(self.activations[i+1])

        for i in range(len(self.weights)):
            self.weights[i] += self.activations[i].T.dot(deltas[i]) * learning_rate / m
            self.biases[i] += np.sum(deltas[i], axis=0, keepdims=True) * learning_rate / m

    def fit(self, X, y, epochs=1000, learning_rate=0.1):
        for _ in range(epochs):
            output = self.forward(X)
            self.backward(X, y, learning_rate)

    def predict(self, X):
        return (self.forward(X) > 0.5).astype(int)

